const text = $input.first().json.text || 'NEON';
const widthInches = $input.first().json.width || 40;
const color = $input.first().json.color || 'pink';
const scene = $input.first().json.scene || 'bar';
const chat_id = $input.first().json.chat_id;

// Convert inches to cm for prompt (visual reference)
const widthCm = Math.round(widthInches * 2.54);

const sceneMap = {
  'bar': 'stylish bar interior with dark walls and ambient lighting',
  'cafe': 'cozy cafe interior with warm atmosphere',
  'street': 'night city street with brick wall building exterior',
  'storefront': 'modern storefront window display',
  'restaurant': 'upscale restaurant interior with elegant decor',
  'shop': 'retail store interior with product displays',
  'office': 'modern office reception area',
  'bedroom': 'stylish bedroom with modern decor',
  'living room': 'contemporary living room interior',
  'garage': 'modern garage or man cave with sports memorabilia'
};

let sceneDesc = sceneMap['bar'];
for (const [key, value] of Object.entries(sceneMap)) {
  if (scene.toLowerCase().includes(key)) {
    sceneDesc = value;
    break;
  }
}

const colorMap = {
  'red': 'crimson red',
  'blue': 'electric blue',
  'pink': 'hot pink',
  'white': 'pure white',
  'green': 'neon green',
  'rgb': 'rainbow multicolor',
  'rainbow': 'rainbow multicolor'
};

const neonColor = colorMap[color.toLowerCase()] || color;

const prompt = `Professional product photography: real LED neon sign reading "${text}" in ${neonColor} glow, mounted on wall in ${sceneDesc}. Sign dimensions approximately ${widthCm}cm wide. Realistic neon lighting effect with soft glow and reflections. High-end commercial photography style, 8K quality.`;

return [{ json: { prompt, text, width: widthInches, color: neonColor, scene: sceneDesc, chat_id } }];

const responseData = $input.item.json.data || $input.item.json;
const taskId = responseData.taskId || responseData.task_id;

if (!taskId) {
  throw new Error('Failed to get taskId from KIE API');
}

const prevData = $('Build Prompt').item.json;

return {
  json: {
    task_id: taskId,
    text: prevData.text,
    color: prevData.color,
    width: prevData.width,
    chat_id: prevData.chat_id,
    attempts: 0
  }
};

const result = $input.item.json;
const savedData = $('Save Task Data').item.json;

if (result.code !== 200 || result.data?.state === 'fail') {
  throw new Error(`KIE Error: ${result.data?.failMsg || result.message}`);
}

let imageUrl = null;
try {
  if (result.data?.resultJson) {
    const parsed = JSON.parse(result.data.resultJson);
    if (parsed.resultUrls?.length > 0) imageUrl = parsed.resultUrls[0];
  }
} catch (e) {
  throw new Error('Failed to parse resultJson');
}

if (!imageUrl) throw new Error('No image URL received');

return {
  json: {
    image_url: imageUrl,
    text: savedData.text,
    color: savedData.color,
    width: savedData.width,
    chat_id: savedData.chat_id
  }
};

const savedData = $('Save Task Data').item.json;
const currentAttempts = $input.item.json.attempts || savedData.attempts || 0;
const attempts = currentAttempts + 1;
const maxAttempts = 24;

if (attempts >= maxAttempts) {
  throw new Error(`Generation timeout exceeded (${maxAttempts * 5} sec). Please try again later.`);
}

return {
  json: {
    task_id: savedData.task_id,
    text: savedData.text,
    color: savedData.color,
    width: savedData.width,
    chat_id: savedData.chat_id,
    attempts: attempts
  }
};
